refsection.programlisting:
      
b=2;
for k=0:9
    d=number_tobary(k,b);
    dstr=strcat(string(d),",");
    r=vandercorput(k,b);
    mprintf("%d [%s] %f\n",k,dstr,r)
end

      
s=4;
p=number_primes100();
for k=1:10
    for j=1:s
        x(j)=vandercorput(k,p(j));
    end
    xstr=strcat(string(x),",");
    mprintf("k=%d, [%s]\n",k,xstr);
end
